definition.script:
pipeline {
    // 1. Definimos el agente donde va a correr
    agent any

    // 2. Herramientas: Cambiamos Gradle por Node.js
    tools {
        nodejs "NodeJS" // Nota: "NodeJS" debe ser el nombre exacto configurado en Administrar Jenkins -> Global Tool Configuration
    }

    // 3. Etapas del Pipeline
    stages {
        stage("Tareas de limpieza e instalacion") {
            steps {

                // Le agregamos explícitamente branch: 'main' antes de la URL
                git branch: 'main', url: 'https://github.com/gonzalolamas/mi-test-node-jenkins.git'


                // En Node.js, para limpiar dependencias viejas o asegurar una instalación limpia:
                // Si estás en Windows usa 'bat', si estás en Linux/Mac usa 'sh'
                bat 'npm clean-install' 
                // Nota: También puedes usar 'bat npm ci' o simplemente 'bat npm install'

                 bat 'node app.js'
            }
        }

        stage("Imprimo cositas") {
            steps {
                echo "Soy un Stage aparte"
                // Aquí podrías correr tu app si quisieras:
                // bat 'node app.js'
            }
        }
    }
}
